// Parse the AI response to extract intent
const aiOutput = $json.output;

// Remove markdown code blocks and parse JSON
const cleanOutput = aiOutput.replace(/```json\n?/g, '').replace(/```/g, '').trim();

try {
  const parsed = JSON.parse(cleanOutput);
  // Temporarily hardcode or skip sessionId to test intent parsing
  return [{
    json: {
      intent: parsed.intent,  // Hardcoded for testing
    }
  }];
} catch (error) {
  return [{
    json: {
      intent: "unclear",
      confidence: 0.0,
      reasoning: "Failed to parse AI response",
      error: error.message,
      raw_output: aiOutput
    }
  }];
}

// Extract intent from Redis GET responses
let extractedIntent = null;
try {
    // Get data from the Edit Fields node
    const inputData = $input.first().json;

    // Handle your data structure
    if (inputData) {
        // Check if we have direct intent field
        if (inputData.intent !== null && inputData.intent !== undefined) {
            extractedIntent = inputData.intent === 'general' ? null : inputData.intent;
        }

        // Check if output indicates completion
        if (inputData.output && typeof inputData.output === 'string') {
            const completionPatterns = [
                /Transaction ID:\s*\d+/,
                /Ticket ID:\s*\d+/,
                /OrderID:\s*\d+/,
                /Service Request Number:\s*SR#\d+/,
                /You're welcome!.*Have a great day/i,
                /Thank you!.*Have a great day!?/i,
                /How can I assist you today?/i,
                /Everything went smoothly during this stage. ✅/i,
                / Everything went smoothly during this stage./i,
                /Status Created On: November 3, 2025, at 10:44 AM/i,
                /The team is keeping a close eye on it./i,
                /Is there anything else I can assist you with/i,
                /Is there anything else I can assist you with?/i,
                /If you have any questions, feel free to ask!/i,
                /Is there anything else I can assist you with?/i,
                /The issue is still pending resolution./i,
                /Feel free to ask if you have any questions!/i,
                /Let me know if you need anything else!/i,
                /If you have any questions, feel free to ask!/i,
                /Great! Let me know if you need further help./i,
                /No problem! Is there anything else I can help you with?/i,
            ];

            const hasCompletion = completionPatterns.some(pattern => 
                pattern.test(inputData.output)
            );

            if (hasCompletion) {
                extractedIntent = null;
            }
        }
    }

    return [{
        json: {
            current_intent: extractedIntent,
            has_existing_intent: !!extractedIntent,
            should_classify: !extractedIntent,
            extracted_successfully: !!extractedIntent
        }
    }];

} catch (error) {
    return [{
        json: {
            current_intent: null,
            has_existing_intent: false,
            should_classify: true,
            extracted_successfully: false,
            error: error.message
        }
    }];
}
